class Solution:
    def countBalanced(self, low, high):
        from functools import lru_cache

        def count_upto(N):
            if N < 1:
                return 0
            s = str(N)
            L = len(s)

            @lru_cache(maxsize=None)
            def dp(i, tight, digits, parity, diff):
                if i == L:
                    return 1 if digits >= 2 and diff == 0 else 0
                limit = int(s[i]) if tight else 9
                total = 0
                for d in range(0, limit + 1):
                    nt = tight and d == limit
                    if digits == 0 and d == 0:
                        total += dp(i + 1, nt, 0, parity, diff)
                    else:
                        ndigits = 2 if digits >= 1 else 1
                        if parity == 0:
                            ndiff = diff + d
                        else:
                            ndiff = diff - d
                        total += dp(i + 1, nt, ndigits, 1 - parity, ndiff)
                return total

            result = dp(0, True, 0, 0, 0)
            dp.cache_clear()
            return result

        return count_upto(high) - count_upto(low - 1)

