var countBalanced = function(low, high) {
    function countUpto(N) {
        if (N < 1) return 0;
        const s = String(N);
        const L = s.length;
        const memo = new Map();

        function dp(i, tight, digits, parity, diff) {
            if (i === L) {
                return (digits >= 2 && diff === 0) ? 1 : 0;
            }
            const key = i + ',' + (tight ? 1 : 0) + ',' + digits + ',' + parity + ',' + diff;
            if (memo.has(key)) return memo.get(key);
            const limit = tight ? (s.charCodeAt(i) - 48) : 9;
            let total = 0;
            for (let d = 0; d <= limit; d++) {
                const nt = tight && d === limit;
                if (digits === 0 && d === 0) {
                    total += dp(i + 1, nt, 0, parity, diff);
                } else {
                    const ndigits = digits >= 1 ? 2 : 1;
                    const ndiff = parity === 0 ? diff + d : diff - d;
                    total += dp(i + 1, nt, ndigits, 1 - parity, ndiff);
                }
            }
            memo.set(key, total);
            return total;
        }

        return dp(0, true, 0, 0, 0);
    }

    return countUpto(high) - countUpto(low - 1);
};
